mapper.update:
update f_review
set
	fr_subject = #{fr_subject},
	fr_star = #{fr_star},
	fr_content = #{fr_content}
where
	id = #{id}
	and f_code = #{f_code}

mapper.select:
select id, f_code, fr_subject, fr_star, fr_createdDate, fr_content from f_review
id = #{id}
f_code = #{f_code}

mapper.delete:
delete from f_review
where
	id = #{id}
	and f_code = #{f_code}
